{code:javascript}
// tags is an array like [{ dc: 'c' }]
// so name is the index i.e 0
// serverTag is an object like { dc: 'c' }
// So the comparison is always undefined != { dc: 'c' } so it never matches

for(var name in tags) {
  if(serverTag[name] != tags[name]) found = false;
}
{code}

