{code:ruby}
require 'mongo'

db = Mongo::Client.new( 'localhost:27018', 'localhost:27019', 'localhost:27020', 'localhost:27021'],
	:database => 'test',
	:read => {
		mode: :secondary_preferred,
		tag_sets: [{ 'dc' => 'c' }]
	}
