This could be a lack of understanding/documentation about how options need to be combined, but it appears that setting slaveOk to true in the connection string or in the collection options does not flow through to the ReadPreferences object, which causes all read queries to fail with:

{ [MongoError: not master and slaveOk=false]
  name: 'MongoError',
  message: 'not master and slaveOk=false',
  '$err': 'not master and slaveOk=false',
  code: 13435 }

Instead, ReadPreferences determines the value of slaveOk based on the readPreference options being set to one of ['primaryPreferred', 'secondary', 'secondaryPreferred', 'nearest'].

For example:

Mongo_Client.connect("mongodb://mongoreport:27017/ec?slaveOk=true", function(error, db)  {
    var collection  = db.collection('my_collection');
    my_collection.find(my_query).toArray(function(err, results) {
        console.log(err);
    })
});

Or:

Mongo_Client.connect("mongodb://mongoreport:27017/ec", function(error, db)  {
    var collection  = db.collection('my_collection',{slaveOk:true});
    my_collection.find(my_query).toArray(function(err, results) {
        console.log(err);
    })
});

Will yield:

{ [MongoError: not master and slaveOk=false]
  name: 'MongoError',
  message: 'not master and slaveOk=false',
  '$err': 'not master and slaveOk=false',
  code: 13435 }

When connecting to a non-master.

Inside /mongodb-core/lib/auth, your try/catch for the Kerberos module is hitting the console with an error if Kerberos is not installed and there is no plan on ever using Kerberos communication. See Below:

try {
  Kerberos = require_optional('kerberos').Kerberos
  // Authentication process for Mongo
  MongoAuthProcess = require_optional('kerberos').processes.MongoAuthProcess
} catch(err) {
  console.dir(err)
}

Please remove the console.dir statement, as it not signaling that there is truly an error, but that Kerberos is just not installed.

